# 输入获取
import math

t = int(input())
# 注意这里需要转float
arr = [list(map(float, input().split())) for i in range(t)]


# 算法入口
def getResult(arr):
    for n, k in arr:
        print(getNK(n, k))


def getNK(n, k):
    # 题目没说异常如何处理,因此我默认输入无异常,比如n=1的话,则k只能取0
    if n == 1:
        return "red"

    # n=2的话,则k只能取0或1
    if n == 2:
        if k == 0:
            return "blue"
        else:
            return "red"

    # 第n个字符串的一半长度half
    half = math.pow(2, n - 2)

    if k >= half:
        return getNK(n - 1, k - half)
    else:
        return "blue" if getNK(n - 1, k) == "red" else "red"


# 调用算法
getResult(arr)
